import * as t from "io-ts";
import { BaseStakeIntent } from "./baseStakeIntent";
import { SubstrateAccountBaseBuildOptions } from "./substrateAccountBaseBuildOptions";
import { intentTypes } from "./intentType";
import { optionalString } from "../../../utils";

/**
 * @title Tao Transfer Stake Intent
 */
export const TaoTransferStakeIntent = t.intersection([
  BaseStakeIntent,
  SubstrateAccountBaseBuildOptions,
  t.type({
    intentType: intentTypes.transferStake,
    originColdkey: optionalString,
    destinationColdkey: t.string,
    hotkey: t.string,
    originNetuid: t.string,
    destinationNetuid: t.string,
    alphaAmount: t.string,
  }),
]);

export type TaoTransferStakeIntent = t.TypeOf<typeof TaoTransferStakeIntent>;
